<script setup>import { ref } from 'vue'; import { useRouter } from 'vue-router'; import { useAuthStore } from '../stores/auth'; const username=ref(''); const password=ref(''); const error=ref(''); const router=useRouter(); const auth=useAuthStore(); async function submit(){ try{ await auth.login(username.value,password.value); router.push('/'); }catch(e){ error.value=e.message; } }</script><template><main class="center"><form class="card" @submit.prevent="submit"><h1>Footprints</h1><p v-if="error" class="error">{{ error }}</p><input v-model="username" placeholder="Username" autocomplete="username"><input v-model="password" type="password" placeholder="Password" autocomplete="current-password"><button>Login</button></form></main></template>
